import Navbar from "../components/Navbar";

export default function LabourDashboard() {

  const requests = [];

  return (

    <div>

      <Navbar />

      <div style={styles.page}>

        <div style={styles.wrapper}>

          <h1 style={styles.title}>Labour Dashboard</h1>
          <p style={styles.subtitle}>Manage incoming requests</p>

          {requests.length === 0 ? (

            <div style={styles.empty}>
              No requests yet
            </div>

          ) : (

            <div style={styles.grid}>

              {requests.map((r, i) => (

                <div key={i} style={styles.card}>

                  <h3>{r.customerName}</h3>

                  <p>{r.workType}</p>
                  <p>{r.date}</p>

                  <input style={styles.input} placeholder="Enter price" />

                  <div style={{ display: "flex", gap: 10 }}>

                    <button style={{ ...styles.smallBtn, background: "green" }}>
                      Accept
                    </button>

                    <button style={{ ...styles.smallBtn, background: "red" }}>
                      Reject
                    </button>

                  </div>

                </div>

              ))}

            </div>

          )}

        </div>

      </div>

    </div>
  );
}

const styles = {

  page: {
    background: "#f4f6f9",
    minHeight: "100vh",
    padding: "30px 10px"
  },

  wrapper: {
    maxWidth: 900,
    margin: "auto"
  },

  title: {
    fontSize: 26,
    marginBottom: 5
  },

  subtitle: {
    color: "#666",
    marginBottom: 20
  },

  grid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fit, minmax(260px, 1fr))",
    gap: 16
  },

  card: {
    background: "white",
    padding: 16,
    borderRadius: 16,
    boxShadow: "0 8px 25px rgba(0,0,0,0.06)"
  },

  input: {
    width: "100%",
    padding: 10,
    marginTop: 8,
    borderRadius: 10,
    border: "1px solid #ddd"
  },

  smallBtn: {
    marginTop: 10,
    padding: "8px 12px",
    border: "none",
    borderRadius: 8,
    color: "white",
    cursor: "pointer"
  },

  empty: {
    textAlign: "center",
    marginTop: 50,
    color: "#777"
  }

};
